// Script Template: condition_group
// 入力モジュールの出力値をグループ番号に分類（多段分岐用）
// プレースホルダー: OpenAI_診療科_初診 = 入力元モジュール名（OpenAI モジュール）
// プレースホルダー: {"産科": "1", "小児科小児外科": "1", "眼科": "1", "脊椎側弯症外科": "1", "整形外科": "1", "人間ドック検診センター": "1", "耳鼻咽喉科": "1", "泌尿器科": "1", "循環器科": "1", "リハビリテーション科": "1", "救急総合診療部": "2", "内視鏡": "2", "集中治療科": "2", "病理診断科": "2", "放射線診断科": "2", "other": "2"} = 値→グループ番号の JSON オブジェクト
// プレースホルダー: 2 = マッピングに該当しない場合のデフォルトグループ番号
// 出力: グループ番号文字列（"1", "2", ... "10"）

var input = $runner.getModuleResult("OpenAI_診療科_初診");
var mapping = {"産科": "1", "小児科小児外科": "1", "眼科": "1", "脊椎側弯症外科": "1", "整形外科": "1", "人間ドック検診センター": "1", "耳鼻咽喉科": "1", "泌尿器科": "1", "循環器科": "1", "リハビリテーション科": "1", "救急総合診療部": "2", "内視鏡": "2", "集中治療科": "2", "病理診断科": "2", "放射線診断科": "2", "other": "2"};
var group = mapping[input];
if (!group) { group = "2"; }
$runner.setResult(group);

// Script Template: condition_group
// 入力モジュールの出力値をグループ番号に分類（多段分岐用）
// プレースホルダー: OpenAI_診療科_再診 = 入力元モジュール名（OpenAI モジュール）
// プレースホルダー: {"人間ドック検診センター": "1", "リハビリテーション科": "1", "救急総合診療部": "1", "内視鏡": "1", "集中治療科": "1", "病理診断科": "1", "放射線診断科": "1", "other": "1"} = 値→グループ番号の JSON オブジェクト
// プレースホルダー: 1 = マッピングに該当しない場合のデフォルトグループ番号
// 出力: グループ番号文字列（"1", "2", ... "10"）

var input = $runner.getModuleResult("OpenAI_診療科_再診");
var mapping = {"人間ドック検診センター": "1", "リハビリテーション科": "1", "救急総合診療部": "1", "内視鏡": "1", "集中治療科": "1", "病理診断科": "1", "放射線診断科": "1", "other": "1"};
var group = mapping[input];
if (!group) { group = "1"; }
$runner.setResult(group);
